var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. AS003M0008-07: <color=#ffd34c>【기록-001】 검토 회의</color>","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE：<color=#ffd34c>ACTIVATED</color>……\\nADC FACTOR：<color=#ffd34c>ALPHA CONFIRMED</color>……\\nCCN No. AS003M0008-07：<color=#ffd34c>【記録-001】 検討会議</color>","ENG":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. AS003M0008-07: <color=#ffd34c>【Record-001】 Review Conference</color>","TWN":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. AS003M0008-07: <color=#ffd34c>【記錄-001】 討論會議</color>","THA":"กระบวนการตรวจสอบประวัติเพื่อความปลอดภัย AEGIS 8 PBLIT: <color=#ffd34c>เปิดทำงาน</color>     \\nADC แฟกเตอร์: <color=#ffd34c>ยืนยันในระดับอัลฟ่า</color>     \\nCCN หมายเลข AS003M0008-07: <color=#ffd34c>[บันทึก-001] การประชุมทบทวน</color>","VTN":"TRÌNH TỰ AN NINH AEGIS 8 PBLIT: <color=#ffd34c>ĐÃ KÍCH HOẠT</color>     \\nTHÔNG SỐ ADC: <color=#ffd34c>XÁC NHẬN ALPHA </color>     \\nCCN Số AS003M0008-07: <color=#ffd34c>[Hồ Sơ-001] Hội Thảo Đánh Giá</color>","SCN":"AEGIS 8 PBLIT安全序列: <color=#ffd34c>激活</color>\\nADC 因素: <color=#ffd34c>阿尔法确认</color>     \\nCCN No. AS003M0008-07: <color=#ffd34c>【记录-001】 讨论会议</color>","DEU":"AEGIS 8 PBLIT-SICHERHEITSSEQUENZ: <color=#ffd34c>AKTIVIERT</color>     \\nADC-FAKTOR: <color=#ffd34c>ALPHA BESTÄTIGT</color>     \\nCCN-Nr. AS003M0008-07: <color=#ffd34c>【Aufzeichnung-001】 Überprüfungskonferenz</color>","FRA":"AEGIS 8 PROTOCOLE DE SÉCURITÉ PBLIT\xA0: <color=#ffd34c>ACTIVÉ</color>     \\nFACTEUR CAD\xA0: <color=#ffd34c>ALPHA CONFIRMÉ</color>     \\nCCN No. AS003M0008-07\xA0: <color=#ffd34c>【Rapport-001】 Conférence d'examen</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"하아......","JPN":"はあ……","ENG":"*Sigh*","TWN":"唉……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"만나자마자 한숨부터 쉬다니, 업무 강도 때문인가?","JPN":"いきなりため息とは。そんなに仕事がきついのかね？","ENG":"Why are you sighing? Is it because of the workload?","TWN":"一見面就嘆氣，是因為工作量太大了嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"어떤 분께서 정보부가 해야 될 일을 저 한 사람에게 모조리 일임하시긴 했죠.","JPN":"あるお方が、本来なら情報部向きの仕事を私に丸ごと一任してくれたのは確かです。","ENG":"Someone dumped all the intelligence work on me.","TWN":"某人把情報部的工作全交給了我。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그런데 정작 일을 맡기신 분은 직원들과 놀러 다니느라 바쁘시고......","JPN":"なのにその方ときたら、仕事を押し付けておきながら社員たちと忙しそうに遊びまわっていまして……","ENG":"And that certain someone has been busy having fun with the employees...","TWN":"但是交代我工作的負責人，卻忙著和員工們玩樂……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"크흠. 흠. 그건 놀러 다니는 게 아니라 잠행일세, 잠행.","JPN":"オッ、オッホン。遊んでいるのではないぞ。あれもれっきとしたスニーキング・​ミッション、潜入任務の類なのだ。","ENG":"Ahem. Ahem. I wasn't having fun. I was working undercover.","TWN":"咳咳，咳。那不是去玩，那是去臥底呀，臥底。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"사장이라면 직원들의 고충도 들어 주고 그래야지.","JPN":"社長たる者、社員の悩みにも耳を傾けねばならんからな。","ENG":"As the CEO, I should be aware of the problems faced by my employees.","TWN":"是老闆的話，就得去聽聽員工們的苦水啊。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"제 허리에서 나는 소리도 귀 기울여 주시죠.","JPN":"私の腰が上げる悲鳴にも、耳を傾けてほしいものです。","ENG":"Could you please be aware of my poor back as well?","TWN":"那您聽聽我的腰發出的聲音。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"......참고하겠네.","JPN":"……善処しよう。","ENG":"I'll keep that in mind.","TWN":"……我會當作參考的。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"입에 발린 말이라도 해 주셔서 감사합니다.","JPN":"建前だとしても、そう言っていただけるとありがたいですね。","ENG":"Thank you for at least pretending to care.","TWN":"儘管是句沒有誠意的客套話，能聽您這麼說真是太感謝了。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그래서...... 무슨 일이길래 세상 다 산 것처럼 그러고 있나?","JPN":"それで……、なぜため息などついていたのだね？悩みがあるなら聞こうではないか。","ENG":"So... what's bothering you?","TWN":"所以……到底是什麼事情讓妳一臉呆樣，一副快要死掉的樣子？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"사장으로서 도울 수 있는 일이라면 나도 거들어 주겠네.","JPN":"社長として助けてやれることならば、私が力になろう。","ENG":"If I can help you out as the CEO, I will do my best.","TWN":"如果是作為老闆能做到的事情，我也會幫你的。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"최근 새로 채용한 직원 때문입니다.","JPN":"最近新しく採用した社員が問題なんです。","ENG":"It's the new recruit.","TWN":"因為最近新來的員工。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"흠, 어디 봄세.","JPN":"ふむ、どれどれ。","ENG":"Hmm, let's see.","TWN":"嗯，我看看。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"알트 소대...... 아, 유진 양이로군. 그 돌격대원.","JPN":"アルト小隊……ああ、シロコ君か。あの切り込み隊員だな。","ENG":"ALT Squad... Oh, it's Eujin. That stormtrooper.","TWN":"阿爾特小隊……喔，劉珍小姐啊，那個突擊隊員。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"전투가 벌어질 때마다 다짜고짜 앞으로 튀어 나가는 점만 빼면 실적은 좋아 보이던데, 다른 문제가 있나?","JPN":"戦闘のたびに後先構わず突っ込んでいくところにさえ目を瞑れば、成果は上々だったはずだが……他にも何か問題があるのかね？","ENG":"Looks like she's doing well, except that she is always charging at the enemy as soon as the battle begins. Are there any other problems?","TWN":"除了每次戰鬥時都會胡亂向前衝以外，業績看起來很不錯啊，有其他問題嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"식비 때문입니다.","JPN":"ズバリ、食費です。","ENG":"Her food expenses.","TWN":"因為她的伙食費。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"식비?","JPN":"食費？","ENG":"Food expenses?","TWN":"伙食費？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};